    domain_lines = raw.split('\n')
} catch e {}

for dline in domain_lines {
    if dline.trim() == '' { continue }
    // 간이 JSON 파싱: 'domain':'XXX' — split 기반
    let mut d_name = ''
    if dline.contains('\'domain\':\'') {
        let d_parts = dline.split('\'domain\':\'')
        if d_parts.len() >= 2 {
            let d_rest = d_parts[1].split('\'')
            if d_rest.len() >= 1 {
                d_name = d_rest[0]
            }
        }
    }
    if d_name == '' { continue }

    // 'keywords':[...] — split 기반 키워드 추출
    if dline.contains('\'keywords\':[') {
        let kw_parts = dline.split('\'keywords\':[')
        if kw_parts.len() >= 2 {
            let kw_body = kw_parts[1].split(']')
            if kw_body.len() >= 1 {
                let kw_items = kw_body[0].split(',')
                for kp in kw_items {
                    let kw_clean = kp.trim().replace('\'', '')
                    if kw_clean != '' && stdin_text.contains(kw_clean) {
