        }
        exact_names = exact_names + to_string(v) + '=' + name
    }
}

// ─── hexa 컴파일/런타임 에러 감지 → pitfalls 자동 추가 ───
if stdin_text.contains('error[Syntax]') || stdin_text.contains('error[Runtime]') || stdin_text.contains('error[Type]') {
    let pitfalls_log = _shared + '/hexa_pitfalls_log.jsonl'
    // 에러 메시지 추출 (첫 줄)
    let mut err_msg = ''
    let err_lines = stdin_text.split('\n')
    let mut ei: i64 = 0
    while ei < err_lines.len() {
        let el = err_lines[ei]
        if el.contains('error[') {
            err_msg = el.trim()
            ei = err_lines.len()
        }
        ei = ei + 1
    }
    if err_msg != '' {
        let ts = exec('date +%Y-%m-%dT%H:%M:%S').trim()
        let entry = '{\'timestamp\':\'' + ts + '\',\'error\':\'' + err_msg.replace('\'', ''') + '\',\'mode\':\'' + mode + '\',\'auto_pitfall\':true}'
        try { append_file(pitfalls_log, entry + '\n') } catch e {}
        // systemMessage로 pitfall 추가 알림
        let pit_msg = '{\'systemMessage\':\'⚠️ ' + project + ' | hexa 에러 → pitfalls 기록: ' + err_msg.replace('\'', ''') + '\'}'
        println(pit_msg)
