// ── 에러 파싱 ──────────────────────────────────────────
fn parse_error(line: string) {
    // error[Syntax]: message --> file:line:col
    let mut file = ''
    let mut msg = ''
    let mut err_line = 0
    let mut err_col = 0

    if contains(line, '-->') {
        let parts = split(line, '-->')
        if len(parts) >= 2 {
            msg = trim(parts[0])
            let loc = trim(parts[1])
            let loc_parts = split(loc, ':')
            if len(loc_parts) >= 3 {
                file = loc_parts[0]
                err_line = int(loc_parts[1])
                err_col = int(loc_parts[2])
            }
        }
    }
    return [file, msg, str(err_line), str(err_col)]
}

// ── 자동 수정 함수들 ──────────────────────────────────
fn fix_block_comments(source: string) {
    // /* ... */ 제거 (중첩 미지원, 단순 패턴)
    let mut result = source
    let mut i = 0
    let mut out = ''
    let mut in_comment = false
    let mut depth = 0

    while i < len(result) {
        if i + 1 < len(result) {
            if result[i] == '/' && result[i + 1] == '*' {
                depth = depth + 1
                in_comment = true
                i = i + 2
                continue
            }
            if result[i] == '*' && result[i + 1] == '/' {
                depth = depth - 1
                if depth == 0 { in_comment = false }
                i = i + 2
                continue
            }
        }
        if !in_comment {
            out = out + result[i]
        }
        i = i + 1
    }
    return out
}

fn fix_semicolons(source: string) {
