        if contains(source, '; ') || ends_with(trim(source), ';') { found = push(found, 'G4:semicolon') }
        if contains(source, ': [int]') || contains(source, ': [i64]') || contains(source, ': [string]') {
            found = push(found, 'G2:array_type')
        }
        if contains(source, '-> (') { found = push(found, 'G1:tuple_return') }

        if len(found) > 0 {
            print(file + ' → ' + join(found, ', '))
