let _autofix = _grammar + '/autofix.json'
let _convergence = _grammar + '/convergence.json'','originalFile':'// self/grammar_autofix.hexa — Hexa 문법 오류 자동 감지+수정
// 모든 수정에 claude code cli 호출 — AI가 컨텍스트 이해하고 수정
//
// 사용:
//   hexa grammar_autofix.hexa --catch 'error[Syntax]: ...' file.hexa
//   hexa grammar_autofix.hexa --scan dir/
//   hexa grammar_autofix.hexa --fix file.hexa
//   hexa grammar_autofix.hexa --fix-all dir/

let args = argv()
if len(args) < 2 {
    eprintln('usage: grammar_autofix.hexa --catch <error> <file>')
    eprintln('       grammar_autofix.hexa --scan <dir>')
    eprintln('       grammar_autofix.hexa --fix <file>')
    eprintln('       grammar_autofix.hexa --fix-all <dir>')
    exit(1)
}

let mode = args[1]
let _home = exec('printenv HOME').trim()
let _hexa = _home + '/Dev/hexa-lang'
let _rules = _hexa + '/shared/hexa_grammar_issues.jsonl'

// ── claude code cli 호출 ────────────────────────────────
fn claude_fix(file: string, error: string) {
    let prompt = 'hexa 문법 오류 자동 수정. ' +
        '에러: ' + error + ' ' +
        '파일: ' + file + ' ' +
        '규칙: ' + _rules + ' 참조. ' +
        '수정 후 원본 의미 100% 보존. 최소 수정만. 설명 없이 수정만.'
    let cmd = 'claude -p '' + prompt + '' --allowedTools Read,Edit --max-turns 3 2>/dev/null'
    let result = exec(cmd)
    print('🤖 ' + file + ' → claude fix 완료')
    return result
}

fn claude_scan_fix(file: string) {
    let prompt = '이 hexa 파일을 파싱 가능하도록 문법 수정. ' +
        '파일: ' + file + ' ' +
        '알려진 이슈: /* block comments */ 제거, 줄끝 ; 제거, ' +
        '-> (T,T) 튜플반환을 struct/배열 반환으로, : [T] 를 : array 로. ' +
        '수정 후 원본 로직 100% 보존. 설명 없이 수정만.'
    let cmd = 'claude -p '' + prompt + '' --allowedTools Read,Edit --max-turns 5 2>/dev/null'
    let result = exec(cmd)
    return result
}

// ── 에러 감지 (빠른 사전 스캔) ──────────────────────────
fn detect_issues(source: string) {
    let mut found = []
    if contains(source, '/*') { found = push(found, 'G3:block_comment') }
    if contains(source, '-> (') { found = push(found, 'G1:tuple_return') }

    let lines = split(source, '\n')
    for line in lines {
        let t = trim(line)
        if ends_with(t, ';') && !contains(t, 'for ') && !contains(t, '//') {
            found = push(found, 'G4:semicolon')
            break
        }
    }

    if contains(source, ': [int]') || contains(source, ': [i64]') ||
       contains(source, ': [float]') || contains(source, ': [string]') ||
       contains(source, ': [bool]') {
        found = push(found, 'G2:array_type')
    }
    return found
}

// ── --catch: PostToolUse hook 에서 호출 ─────────────────
if mode == '--catch' {
    if len(args) < 4 {
        eprintln('usage: --catch <error_msg> <file>')
        exit(1)
    }
    let error = args[2]
    let file = args[3]
    if !contains(error, 'error[') { exit(0) }

    print('🔧 grammar-catch: ' + file)
    claude_fix(file, error)
    exit(0)
}

// ── --scan: 디렉토리 스캔 (수정 안 함) ──────────────────
if mode == '--scan' {
    let dir = args[2]
    let files = glob(dir + '/*.hexa')
    let mut issue_count = 0

    for file in files {
        let source = read_file(file)
        let found = detect_issues(source)
        if len(found) > 0 {
            print(file + ' → ' + join(found, ', '))
            issue_count = issue_count + 1
        }
    }
    print('\n총 ' + str(issue_count) + ' 파일에 문법 이슈')
    exit(0)
}

// ── --fix: 단일 파일 claude 수정 ────────────────────────
if mode == '--fix' {
    let file = args[2]
    let source = read_file(file)
    let found = detect_issues(source)

    if len(found) == 0 {
        print('✅ ' + file + ' — 이슈 없음')
        exit(0)
    }

    print('🔍 ' + file + ' → ' + join(found, ', '))
    claude_scan_fix(file)
    print('🤖 ' + file + ' → claude fix 완료')
    exit(0)
}

// ── --fix-all: 디렉토리 전체 claude 수정 ────────────────
if mode == '--fix-all' {
    let dir = args[2]
    let files = glob(dir + '/*.hexa')
    let mut total = 0

    for file in files {
        let source = read_file(file)
        let found = detect_issues(source)
        if len(found) > 0 {
            print('🔍 ' + file + ' → ' + join(found, ', '))
            claude_scan_fix(file)
            print('🤖 ' + file + ' done')
            total = total + 1
        }
    }
    print('\n총 ' + str(total) + ' 파일 claude 수정 완료')
    exit(0)
}

// ── 기본: 에러 텍스트 직접 전달 ─────────────────────────
let file = args[1]
let error_text = if len(args) >= 3 { args[2] } else { '' }

if error_text != '' {
    claude_fix(file, error_text)
} else {
    // 에러 없이 파일만 → 스캔+수정
    let source = read_file(file)
    let found = detect_issues(source)
    if len(found) > 0 {
        print('🔍 ' + join(found, ', '))
        claude_scan_fix(file)
        print('🤖 완료')
    } else {
        print('✅ 이슈 없음')
    }
}
