    let output = read_stdin()

    // hexa 에러 패턴 감지
    let has_error = output.contains('error[Syntax]') || output.contains('error[Type]') || output.contains('error[Parse]') || output.contains('문법')
    if has_error == false { return }

    // 파일:줄번호 추출
    let lines = output.split('\n')
    let mut file = ''
    let mut i = 0
    while i < len(lines) {
        let line = lines[i]
        if line.contains('.hexa:') {
            let parts = line.split(' ')
            let mut j = 0
            while j < len(parts) {
                if parts[j].contains('.hexa:') {
                    file = parts[j]
                    break
                }
                j = j + 1
            }
            if file != '' { break }
        }
        i = i + 1
