        if lines[i].contains('error[') {
            err = lines[i].trim()
            break
        }
        i = i + 1
    }

    // 문법 ID 분류
    let mut gid = '?'
    if err.contains('Semicolon') { gid = 'G6' }
    if err.contains('-> (') || err.contains('RParen') { gid = 'G1' }
    if err.contains('block comment') || err.contains('/*') { gid = 'G3' }
    if err.contains(': [') || err.contains('expected identifier') { gid = 'G2' }
    if err.contains('Struct{}') || err.contains('struct literal') { gid = 'G5' }
    if err.contains('builtin') || err.contains('did you mean') { gid = 'G7' }

    let safe_err = err.replace('\'', ''')
    let safe_file = file.replace('\'', ''')

