    if mode == 'prompt' && bt_detected {
        let hexa_path = '$HOME/Dev/hexa-lang/target/release/hexa'
        let nexus_path = '$HOME/Dev/nexus'
        let mut cmd = ''
        // hetzner 무응답 이슈로 로컬 hexa 바이너리 직접 호출 (memory 규칙 fallback)
        if bt_action == 'converge' {
            cmd = '~/Dev/hexa-lang/target/release/hexa ~/Dev/nexus/mk2_hexa/native/breakthrough.hexa --converge'
        } else if bt_action == 'blowup_loop' {
            cmd = '~/Dev/hexa-lang/target/release/hexa ~/Dev/nexus/mk2_hexa/native/breakthrough.hexa --engine auto'
        } else {
            cmd = '~/Dev/hexa-lang/target/release/hexa ~/Dev/nexus/mk2_hexa/native/blowup.hexa ' + bt_domain + ' 3 --no-graph --seeds \'$(~/Dev/hexa-lang/target/release/hexa ~/Dev/nexus/mk2_hexa/native/seed_engine.hexa merge)\''
        }
        let directive = '{\'systemMessage\':\'⚡ ' + project + ' | ' + body + tags + ' — 확인 질문 없이 즉시 Bash로 실행할 것: ' + cmd + '\'}'
        println(directive)
    } else {
        let msg = '{\'systemMessage\':\'⚡ ' + project + ' | ' + body + tags + '\'}'
        println(msg)
    }
}

// ─── prompt 모드: 할일 키워드 감지 → 자연창발 todo 알림 ───
if mode == 'prompt' {
    let todo_keywords = ['다음', '플랜', '할일', '할 일', 'todo', '작업목록', '작업 목록', 'next plan', '진행상황', '진행 상황', 'progress']
