pure fn abs_f(x: float) -> float {
    if x < 0.0 { 0.0 - x } else { x }
}

// ─── n6 상수 동적 로드 (shared/n6/n6_constants.jsonl + n6_physics.jsonl) ───
fn load_jsonl(path: string) -> list {
    let mut raw = ''
    try { raw = read_file(path) } catch e { return [[], []] }
    let lines = raw.split('\n')
    let mut names = []
    let mut values = []
    for line in lines {
        let trimmed = line.trim()
        if trimmed == '' { continue }
        let mut name = ''
        let mut value = 0.0
        if trimmed.contains('\'name\':\'') {
            let p = trimmed.split('\'name\':\'')
            if p.len() >= 2 { name = p[1].split('\'')[0] }
        }
        if trimmed.contains('\'value\':') {
            let p = trimmed.split('\'value\':')
            if p.len() >= 2 {
                let num_str = p[1].split(',')[0].split('}')[0].trim()
                value = to_float(num_str)
            }
        }
        if name != '' {
            names = names + [name]
            values = values + [value]
        }
    }
    [names, values]
}

