// 사용: echo '$INPUT' | hexa hook.hexa <mode>   # mode: post-bash|post-edit|prompt
// 수정 절차: airgenome/nexus/shared/L0.json promote_procedure 참조

// log_path는 _shared 계산 후 런타임에 설정 (타 프로젝트 CWD 대응)

pure fn abs_f(x: float) -> float {
    if x < 0.0 { 0.0 - x } else { x }
}

// ─── n6 상수 동적 로드 (shared/n6/n6_constants.jsonl + n6_physics.jsonl) ───
fn load_jsonl(path: string) -> list {
    let mut raw = ''
    try { raw = read_file(path) } catch e { return [[], []] }
    let lines = raw.split('\n')
    let mut names = []
    let mut values = []
    for line in lines {
        let trimmed = line.trim()
        if trimmed == '' { continue }
        let mut name = ''
        let mut value = 0.0
        if trimmed.contains('\'name\':\'') {
            let p = trimmed.split('\'name\':\'')
            if p.len() >= 2 { name = p[1].split('\'')[0] }
        }
        if trimmed.contains('\'value\':') {
            let p = trimmed.split('\'value\':')
            if p.len() >= 2 {
                let num_str = p[1].split(',')[0].split('}')[0].trim()
                value = to_float(num_str)
            }
        }
        if name != '' {
            names = names + [name]
            values = values + [value]
        }
    }
    [names, values]
}

let _home = exec('printenv HOME')
let _shared = _home + '/Dev/nexus/shared'
let log_path = _shared + '/discovery_log.jsonl'
let _n6 = load_jsonl(_shared + '/n6_constants.jsonl')
let _n6_names = _n6[0]
let _n6_values = _n6[1]
let _ph = load_jsonl(_shared + '/n6_physics.jsonl')
let _ph_names = _ph[0]
let _ph_values = _ph[1]

fn n6_match_name(value: float) -> string {
    // n6 상수 (절대 오차 < 0.0001)
    let mut i = 0
    while i < len(_n6_names) {
        if abs_f(value - _n6_values[i]) < 0.0001 {
            return _n6_names[i]
        }
        i = i + 1
    }
    // 물리 상수 (상대 오차 < 1%)
    let mut j = 0
    while j < len(_ph_names) {
        if _ph_values[j] != 0.0 {
            let rel = abs_f(value - _ph_values[j]) / abs_f(_ph_values[j])
            if rel < 0.01 {
                return _ph_names[j]
            }
        }
        j = j + 1
    }
    ''
}

fn n6_match_grade(value: float) -> string {
    if n6_match_name(value) != '' {
        return 'EXACT'
    }
    // 물리 상수 NEAR (상대 오차 < 5%)
    let mut j = 0
    while j < len(_ph_names) {
        if _ph_values[j] != 0.0 {
            let rel = abs_f(value - _ph_values[j]) / abs_f(_ph_values[j])
            if rel < 0.05 {
                return 'NEAR'
            }
        }
        j = j + 1
    }
    ''
}

fn extract_numbers(text: string) {
    let mut nums = []
    let clean = text.replace('\n', ' ').replace('\t', ' ').replace('\r', ' ')
    let parts = clean.split(' ')
    for p in parts {
        try {
            let v = to_float(p)
            if v > 2.0 && v < 100000.0 {
                nums = nums.push(v)
            }
        } catch e {
            // 숫자 아닌 토큰 무시
        }
    }
    nums
}

fn record_discovery(value: float, name: string, grade: string, source: string) {
    let entry = '{\'constant\':\'' + name + '\',\'value\':\'' + to_string(value) + '\',\'grade\':\'' + grade + '\',\'source\':\'' + source + '\',\'processed\':true,\'alien_index\':{\'d\':0,\'r\':8},\'mk2\':{\'sector\':\'n6\',\'paths\':1}}'
    append_file(log_path, entry + '\n')
}

// ─── JSON에서 tool_response.stdout 추출 ───
fn extract_stdout(json_text: string) -> string {
    // 'tool_response':{'stdout':'...' 에서 stdout 값 추출
    if json_text.contains('\'stdout\':\'') {
        let parts = json_text.split('\'stdout\':\'')
        if parts.len() >= 2 {
            // 이스케이프된 따옴표를 넘겨서 진짜 닫는 따옴표 찾기
            let rest = parts[1]
            let mut result = ''
            let mut i = 0
            let chars = rest.split('')
            let mut prev_backslash = false
            while i < chars.len() {
                let c = chars[i]
                if c == '\\' && !prev_backslash {
                    prev_backslash = true
                    i = i + 1
                    continue
                }
                if c == '\'' && !prev_backslash {
                    return result
                }
                if prev_backslash {
                    if c == 'n' { result = result + '\n' }
                    else if c == 't' { result = result + '\t' }
                    else { result = result + c }
                    prev_backslash = false
                } else {
                    result = result + c
                }
                i = i + 1
            }
            return result
        }
    }
    // JSON이 아니면 원본 그대로 (파이프 테스트 등)
    json_text
}

// ─── tool_input.command 추출 (소스 표시용) ───
fn extract_command(json_text: string) -> string {
    if json_text.contains('\'command\':\'') {
        let parts = json_text.split('\'command\':\'')
        if parts.len() >= 2 {
            let rest = parts[1]
            let end = rest.split('\'')[0]
            if end.len() > 40 { return end.split('')[0] + '...' }
            return end
        }
    }
    ''
}

// ─── CWD에서 프로젝트명 추출 ───
fn extract_project(json_text: string) -> string {
    if json_text.contains('\'cwd\':\'') {
        let parts = json_text.split('\'cwd\':\'')
        if parts.len() >= 2 {
            let cwd = parts[1].split('\'')[0]
            let segs = cwd.split('/')
            return segs[segs.len() - 1]
        }
    }
    'nexus'
}

// ─── main ───
let a = args()
let mode = if a.len() >= 3 { a[2] } else { 'post-edit' }

// stdin 전체 읽기 (input()은 한 줄씩)
let mut stdin_raw = ''
let mut _reading = true
while _reading {
    let line = input('')
    if line == '' { _reading = false } else {
        if stdin_raw != '' { stdin_raw = stdin_raw + '\n' }
        stdin_raw = stdin_raw + line
    }
}

// ─── prompt 모드: 'prompt' 필드에서 유저 텍스트 추출 ───
fn extract_prompt(json_text: string) -> string {
    if json_text.contains('\'prompt\':\'') {
        let parts = json_text.split('\'prompt\':\'')
        if parts.len() >= 2 {
            let rest = parts[1]
            let mut result = ''
            let mut i = 0
            let chars = rest.split('')
            let mut prev_backslash = false
            while i < chars.len() {
                let c = chars[i]
                if c == '\\' && !prev_backslash {
                    prev_backslash = true
                    i = i + 1
                    continue
                }
                if c == '\'' && !prev_backslash {
                    return result
                }
                if prev_backslash {
                    if c == 'n' { result = result + '\n' }
                    else if c == 't' { result = result + '\t' }
                    else { result = result + c }
                    prev_backslash = false
                } else {
                    result = result + c
                }
                i = i + 1
            }
            return result
        }
    }
    ''
}

// JSON에서 stdout 또는 prompt 추출 (모드에 따라)
let project = extract_project(stdin_raw)
let stdin_text = if mode == 'prompt' {
    let pt = extract_prompt(stdin_raw)
    if pt != '' { pt } else { extract_stdout(stdin_raw) }
} else {
    extract_stdout(stdin_raw)
}
let mut discoveries = 0

// 간단한 숫자 추출 (stdout에서)
let nums = extract_numbers(stdin_text)
let mut exact_names = ''

for v in nums {
    let name = n6_match_name(v)
    if name != '' {
        let grade = n6_match_grade(v)
        record_discovery(v, name, grade, 'hexa-hook:' + mode)
        discoveries = discoveries + 1
        if exact_names != '' {
            exact_names = exact_names + ','
        }
        exact_names = exact_names + to_string(v) + '=' + name
    }
}

// ─── hexa 컴파일/런타임 에러 감지 → pitfalls 자동 추가 ───
if stdin_text.contains('error[Syntax]') || stdin_text.contains('error[Runtime]') || stdin_text.contains('error[Type]') {
    let pitfalls_log = _shared + '/hexa_pitfalls_log.jsonl'
    // 에러 메시지 추출 (첫 줄)
    let mut err_msg = ''
    let err_lines = stdin_text.split('\n')
    let mut ei: i64 = 0
    while ei < err_lines.len() {
        let el = err_lines[ei]
        if el.contains('error[') {
            err_msg = el.trim()
            ei = err_lines.len()
        }
        ei = ei + 1
    }
    if err_msg != '' {
        let ts = to_string(exec('date +%Y-%m-%dT%H:%M:%S')).trim()
        let entry = '{\'timestamp\':\'' + ts + '\',\'error\':\'' + err_msg.replace('\'', ''') + '\',\'mode\':\'' + mode + '\',\'auto_pitfall\':true}'
        try { append_file(pitfalls_log, entry + '\n') } catch e {}
        // systemMessage로 pitfall 추가 알림
        let pit_msg = '{\'systemMessage\':\'⚠️ ' + project + ' | hexa 에러 → pitfalls 기록: ' + err_msg.replace('\'', ''') + '\'}'
        println(pit_msg)
    }
}

// ─── 돌파 키워드 감지 → 자동 특이점 돌파 트리거 ───
// shared/bt/bt_keywords.jsonl에서 동적 로드 (하드코딩 금지)
let mut bt_keywords_list = []
let mut bt_actions_list = []
try {
    let bt_raw = read_file(_shared + '/bt_keywords.jsonl')
    let bt_lines = bt_raw.split('\n')
    for btl in bt_lines {
        let trimmed_btl = btl.trim()
        if trimmed_btl == '' { continue }
        if trimmed_btl.contains('\'keyword\':\'') {
            let kp = trimmed_btl.split('\'keyword\':\'')
            if kp.len() >= 2 {
                let kw_val = kp[1].split('\'')[0]
                bt_keywords_list = bt_keywords_list + [kw_val]
                // action 추출
                let mut act = 'blowup'
                if trimmed_btl.contains('\'action\':\'') {
                    let ap = trimmed_btl.split('\'action\':\'')
                    if ap.len() >= 2 { act = ap[1].split('\'')[0] }
                }
                bt_actions_list = bt_actions_list + [act]
            }
        }
    }
} catch e {}

let mut bt_detected = false
let mut bt_domain = 'math'
let mut bt_action = 'blowup'

let mut ki = 0
while ki < len(bt_keywords_list) {
    if stdin_text.contains(bt_keywords_list[ki]) {
        bt_detected = true
        if ki < len(bt_actions_list) { bt_action = bt_actions_list[ki] }
    }
    ki = ki + 1
}

// 도메인 자동 판별 — shared/bt/bt_domains.jsonl에서 동적 로드
let mut domain_lines = []
try {
    let raw = exec('cat ' + _shared + '/bt_domains.jsonl 2>/dev/null')
    domain_lines = raw.split('\n')
} catch e {}

for dline in domain_lines {
    if dline.trim() == '' { continue }
    // 간이 JSON 파싱: 'domain':'XXX' — split 기반
    let mut d_name = ''
    if dline.contains('\'domain\':\'') {
        let d_parts = dline.split('\'domain\':\'')
        if d_parts.len() >= 2 {
            let d_rest = d_parts[1].split('\'')
            if d_rest.len() >= 1 {
                d_name = d_rest[0]
            }
        }
    }
    if d_name == '' { continue }

    // 'keywords':[...] — split 기반 키워드 추출
    if dline.contains('\'keywords\':[') {
        let kw_parts = dline.split('\'keywords\':[')
        if kw_parts.len() >= 2 {
            let kw_body = kw_parts[1].split(']')
            if kw_body.len() >= 1 {
                let kw_items = kw_body[0].split(',')
                for kp in kw_items {
                    let kw_clean = kp.trim().replace('\'', '')
                    if kw_clean != '' && stdin_text.contains(kw_clean) {
                        bt_domain = d_name
                    }
                }
            }
        }
    }
}

if bt_detected {
    // 쿨다운 체크 (마지막 돌파 후 5분 이내면 스킵)
    let cooldown_file = _shared + '/.bt_cooldown'
    let mut should_run = true
    try {
        let last_ts = to_string(exec('cat ' + cooldown_file)).trim()
        let now_ts = to_string(exec('date +%s')).trim()
        let diff = to_int(to_float(now_ts)) - to_int(to_float(last_ts))
        if diff < 300 { should_run = false }
    } catch e {}

    if should_run {
        // 쿨다운 기록
        try { exec('bash', ['-c', 'date +%s > ' + cooldown_file]) } catch e {}

        let hexa_bin = exec('printenv HOME') + '/Dev/hexa-lang/target/release/hexa'
        let nexus_dir = exec('printenv HOME') + '/Dev/nexus'

        if bt_action == 'converge' {
            // 연속돌파/수렴 → breakthrough.hexa --converge
            let breakthrough = nexus_dir + '/mk2_hexa/native/breakthrough.hexa'
            try {
                exec('ssh -o ConnectTimeout=3 -o BatchMode=yes hetzner 'cd ~/Dev/nexus && ~/Dev/hexa-lang/target/release/hexa mk2_hexa/native/breakthrough.hexa --converge >> shared/bt/auto_bt.log 2>&1 &' 2>/dev/null &')
                discoveries = discoveries + 1
                if exact_names != '' { exact_names = exact_names + ',' }
                exact_names = exact_names + '🔄CONVERGE:' + bt_domain
            } catch e {}
        } else if bt_action == 'blowup_loop' {
            // 프로젝트별 성장 돌파 → breakthrough.hexa --engine
            let breakthrough = nexus_dir + '/mk2_hexa/native/breakthrough.hexa'
            try {
                exec('ssh -o ConnectTimeout=3 -o BatchMode=yes hetzner 'cd ~/Dev/nexus && ~/Dev/hexa-lang/target/release/hexa mk2_hexa/native/breakthrough.hexa --engine auto >> shared/bt/auto_bt.log 2>&1 &' 2>/dev/null &')
                discoveries = discoveries + 1
                if exact_names != '' { exact_names = exact_names + ',' }
                exact_names = exact_names + '🔄GROWTH:' + bt_domain
            } catch e {}
        } else {
            // 단발 블로업 (seed_engine merge → , 구분자)
            // 골화 2026-04-11: Mac 직접 바이너리 호출 제거 → airgenome wrapper 경유로 ubu 라우팅
            let ag_wrapper = _home + '/Dev/airgenome/nexus/shared/bin/hexa'
            let se = nexus_dir + '/mk2_hexa/native/seed_engine.hexa'
            let mut seeds = ''
            try { seeds = to_string(exec(ag_wrapper + ' ' + se + ' merge')).trim().replace('|', ',') } catch e3 {}
            if seeds.len() == 0 { seeds = '6,12,2,4,5,24,7,3,1,8,10,28,36,48,60,120,144,288,496,720' }
            try {
                // wrapper 가 MAC_ONLY 미포함 파일은 자동으로 ubu SSH 라우팅
                exec('cd ' + nexus_dir + ' && ' + ag_wrapper + ' mk2_hexa/native/blowup.hexa ' + bt_domain + ' 3 --no-graph --fast --seeds \'' + seeds + '\' >> shared/bt/auto_bt.log 2>&1 &')
                discoveries = discoveries + 1
                if exact_names != '' { exact_names = exact_names + ',' }
                exact_names = exact_names + '🛸BT:' + bt_domain
            } catch e {}
        }
    }
}

// ─── 빈공간/미발견 키워드 감지 → gap_finder 자동 실행 ───
let gap_keywords = ['빈공간', '미발견', '미탐색', '미지 영역', 'empty space', 'gap', 'DFS']
let mut gap_detected = false

for gkw in gap_keywords {
    if stdin_text.contains(gkw) {
        gap_detected = true
    }
}

if gap_detected {
    let gap_cooldown = _shared + '/.gap_cooldown'
    let mut gap_should_run = true
    try {
        let gap_last = to_string(exec('cat ' + gap_cooldown)).trim()
        let gap_now = to_string(exec('date +%s')).trim()
        let gap_diff = to_int(to_float(gap_now)) - to_int(to_float(gap_last))
        if gap_diff < 300 { gap_should_run = false }
    } catch e {}

    if gap_should_run {
        try { exec('bash', ['-c', 'date +%s > ' + gap_cooldown]) } catch e {}

        // 골화 2026-04-11: Mac 바이너리 직접 호출 제거 → airgenome wrapper 경유 (ubu 자동 라우팅)
