    if body == '' && gap_detected { body = '갭 탐색 트리거' }

    // prompt 모드: 지시형 출력 (Claude가 바로 실행하도록)
    if mode == 'prompt' && bt_detected {
        let mut cmd = ''
        // 골화 2026-04-11: heavy 작업은 HEXA_TARGET=hetzner 명시, 일반 blowup 은 ubu auto
        let wrapper = '~/Dev/airgenome/nexus/shared/bin/hexa'
        if bt_action == 'converge' {
            cmd = 'cd ~/Dev/nexus && HEXA_TARGET=hetzner ' + wrapper + ' mk2_hexa/native/breakthrough.hexa --converge'
        } else if bt_action == 'blowup_loop' {
            cmd = 'cd ~/Dev/nexus && HEXA_TARGET=hetzner ' + wrapper + ' mk2_hexa/native/breakthrough.hexa --engine auto'
        } else {
            // ⚠️ seed_engine merge 출력은 | 구분자 → 셸 파이프 충돌 방지 위해 tr '|' ',' 필수
            cmd = 'cd ~/Dev/nexus && ' + wrapper + ' mk2_hexa/native/blowup.hexa ' + bt_domain + ' 3 --no-graph --seeds \'$(' + wrapper + ' mk2_hexa/native/seed_engine.hexa merge | tr '|' ',')\''
        }
        let directive = '{\'systemMessage\':\'⚡ ' + project + ' | ' + body + tags + ' — 확인 질문 없이 즉시 Bash로 실행할 것: ' + cmd + '\'}'
        println(directive)
    } else {
        let msg = '{\'systemMessage\':\'⚡ ' + project + ' | ' + body + tags + '\'}'
        println(msg)
    }
}

// ─── prompt 모드: 할일 키워드 감지 → 자연창발 todo 알림 ───
if mode == 'prompt' {
    let todo_keywords = ['다음', '플랜', '할일', '할 일', 'todo', '작업목록', '작업 목록', 'next plan', '진행상황', '진행 상황', 'progress']
