fn n6_match_name(value: float) -> string {
    // n6 상수 (절대 오차 < 0.0001)
    let mut i = 0
    while i < len(_n6_names) {
        if abs_f(value - _n6_values[i]) < 0.0001 {
            return _n6_names[i]
        }
        i = i + 1
    }
    // 물리 상수 (상대 오차 < 1%)
    let mut j = 0
    while j < len(_ph_names) {
        if _ph_values[j] != 0.0 {
            let rel = abs_f(value - _ph_values[j]) / abs_f(_ph_values[j])
            if rel < 0.01 {
                return _ph_names[j]
            }
        }
        j = j + 1
    }
    ''
}

fn n6_match_grade(value: float) -> string {
    if n6_match_name(value) != '' {
        return 'EXACT'
    }
    // 물리 상수 NEAR (상대 오차 < 5%)
    let mut j = 0
    while j < len(_ph_names) {
        if _ph_values[j] != 0.0 {
            let rel = abs_f(value - _ph_values[j]) / abs_f(_ph_values[j])
            if rel < 0.05 {
                return 'NEAR'
            }
        }
        j = j + 1
    }
    ''
}

fn extract_numbers(text: string) {
    let mut nums = []
    let clean = text.replace('\n', ' ').replace('\t', ' ').replace('\r', ' ')
    let parts = clean.split(' ')
    for p in parts {
        try {
            let v = to_float(p)
            if v > 2.0 && v < 100000.0 {
                nums = nums.push(v)
            }
        } catch e {
            // 숫자 아닌 토큰 무시
        }
    }
    nums
}

fn record_discovery(value: float, name: string, grade: string, source: string) {
    let entry = '{\'constant\':\'' + name + '\',\'value\':\'' + to_string(value) + '\',\'grade\':\'' + grade + '\',\'source\':\'' + source + '\',\'processed\':true,\'alien_index\':{\'d\':0,\'r\':8},\'mk2\':{\'sector\':\'n6\',\'paths\':1}}'
    append_file(log_path, entry + '\n')
}

// ─── JSON에서 tool_response.stdout 추출 ───
fn extract_stdout(json_text: string) -> string {
    // 'tool_response':{'stdout':'...' 에서 stdout 값 추출
    if json_text.contains('\'stdout\':\'') {
        let parts = json_text.split('\'stdout\':\'')
        if parts.len() >= 2 {
            // 이스케이프된 따옴표를 넘겨서 진짜 닫는 따옴표 찾기
            let rest = parts[1]
            let mut result = ''
            let mut i = 0
            let chars = rest.split('')
            let mut prev_backslash = false
            while i < chars.len() {
                let c = chars[i]
                if c == '\\' && !prev_backslash {
                    prev_backslash = true
                    i = i + 1
                    continue
                }
                if c == '\'' && !prev_backslash {
                    return result
                }
                if prev_backslash {
                    if c == 'n' { result = result + '\n' }
                    else if c == 't' { result = result + '\t' }
                    else { result = result + c }
                    prev_backslash = false
                } else {
                    result = result + c
                }
                i = i + 1
            }
            return result
        }
    }
    // JSON이 아니면 원본 그대로 (파이프 테스트 등)
    json_text
}

// ─── tool_input.command 추출 (소스 표시용) ───
fn extract_command(json_text: string) -> string {
    if json_text.contains('\'command\':\'') {
        let parts = json_text.split('\'command\':\'')
        if parts.len() >= 2 {
            let rest = parts[1]
            let end = rest.split('\'')[0]
            if end.len() > 40 { return end.split('')[0] + '...' }
            return end
        }
    }
    ''
}

// ─── CWD에서 프로젝트명 추출 ───
fn extract_cwd(json_text: string) -> string {
    if json_text.contains('\'cwd\':\'') {
        let parts = json_text.split('\'cwd\':\'')
        if parts.len() >= 2 {
            return parts[1].split('\'')[0]
        }
    }
    ''
}

fn extract_project(json_text: string) -> string {
    let cwd = extract_cwd(json_text)
    if cwd != '' {
        let segs = cwd.split('/')
        return segs[segs.len() - 1]
    }
    'nexus'
}

