// ─── 돌파 키워드 자체 창발 — bt_keywords.jsonl 의존도 0% ───
// ⚠️ 유저 입력에서 '돌파/breakthrough/blowup' 감지 → 앞 키워드가 도메인
// ⚠️ action 판별: '연속/수렴/converge' → converge, '성장/growth' → blowup_loop, 그 외 → blowup
let mut bt_detected = false
let mut bt_domain = 'math'
let mut bt_action = 'blowup'

// 돌파 감지 (자체 창발 — 목록 의존 없음)
// ⚠️ 긴 텍스트(CLAUDE.md 등)에서 오작동 방지: 200자 이하만 감지
if stdin_text.len() < 200 {
    if stdin_text.contains('돌파') || stdin_text.contains('breakthrough') || stdin_text.contains('blowup') || stdin_text.contains('특이점') || stdin_text.contains('singularity') || stdin_text.contains('창발') || stdin_text.contains('emergence') {
        bt_detected = true
    }
}

// action 자체 창발
if bt_detected {
    if stdin_text.contains('연속돌파') || stdin_text.contains('연속 돌파') || stdin_text.contains('수렴') || stdin_text.contains('converge') {
        bt_action = 'converge'
    } else if stdin_text.contains('성장') || stdin_text.contains('growth') || stdin_text.contains('폭발적') || stdin_text.contains('explosive') {
        bt_action = 'blowup_loop'
    }
}

// ⚠️ 도메인 자체 창발 — bt_domains.jsonl 의존도 0%, 키워드 추출 아님
// 유저 문장 전체를 도메인으로 사용 ('돌파' 제거 후 전문)
// 예: '아이디어 돌파' → domain='아이디어'
