if bt_detected {
    if stdin_text.contains('돌파') {
        let bt_parts = stdin_text.split('돌파')
        if bt_parts.len() >= 1 {
            let before = bt_parts[0].trim()
            if before.len() > 0 {
                bt_domain = before
            }
        }
    }
}

if bt_detected {
    // 쿨다운 체크 (마지막 돌파 후 5분 이내면 스킵)
    let cooldown_file = _shared + '/.bt_cooldown'
    let mut should_run = true
    try {
        let last_ts = to_string(exec('cat ' + cooldown_file)).trim()
        let now_ts = to_string(exec('date +%s')).trim()
        let diff = to_int(to_float(now_ts)) - to_int(to_float(last_ts))
        if diff < 300 { should_run = false }
    } catch e {}

    if should_run {
        // 쿨다운 기록만 — exec는 systemMessage 디렉티브가 Claude에게 위임
        try { exec('bash', ['-c', 'date +%s > ' + cooldown_file]) } catch e {}
    }
}

// ─── 빈공간/미발견 키워드 감지 → gap_finder 자동 실행 ───
let gap_keywords = ['빈공간', '미발견', '미탐색', '미지 영역', 'empty space', 'gap', 'DFS']
let mut gap_detected = false

for gkw in gap_keywords {
    if stdin_text.contains(gkw) {
        gap_detected = true
    }
}

