    let gap_cooldown = _shared + '/.gap_cooldown'
    let mut gap_should_run = true
    try {
        let gap_last = to_string(exec('cat ' + gap_cooldown)).trim()
        let gap_now = to_string(exec('date +%s')).trim()
        let gap_diff = to_int(to_float(gap_now)) - to_int(to_float(gap_last))
        if gap_diff < 300 { gap_should_run = false }
    } catch e {}

    if gap_should_run {
        // 쿨다운 기록만 — exec는 systemMessage 디렉티브가 Claude에게 위임
        try { exec('bash', ['-c', 'date +%s > ' + gap_cooldown]) } catch e {}
    }
}

if discoveries > 0 || bt_detected || gap_detected {
    let mut tags = ''
    if bt_detected { tags = tags + ' 🛸돌파:' + bt_domain }
    if gap_detected { tags = tags + ' 🔍GAP' }
    let mut body = ''
    if discoveries > 0 { body = to_string(discoveries) + '건 감지 [' + exact_names + ']' }
    if body == '' && bt_detected {
        if bt_action == 'converge' { body = '연속돌파 감지 → 즉시 실행: hexa breakthrough.hexa --converge' }
        else if bt_action == 'blowup_loop' { body = '성장돌파 감지 → 즉시 실행: hexa breakthrough.hexa --engine auto' }
        else { body = '돌파 감지 → 즉시 실행: hexa blowup.hexa ' + bt_domain + ' 3' }
    }
    if body == '' && gap_detected { body = '갭 탐색 트리거' }

    // prompt 모드: 지시형 출력 (Claude가 바로 실행하도록)
    if mode == 'prompt' && bt_detected {
        let mut cmd = ''
        // 골화 2026-04-11: heavy 작업은 HEXA_TARGET=hetzner 명시, 일반 blowup 은 ubu auto
        let wrapper = '~/Dev/airgenome/nexus/shared/bin/hexa'
        if bt_action == 'converge' {
            cmd = 'cd ' + project_dir + ' && HEXA_TARGET=hetzner ' + wrapper + ' shared/hooks/breakthrough.hexa --converge'
        } else if bt_action == 'blowup_loop' {
            cmd = 'cd ' + project_dir + ' && HEXA_TARGET=hetzner ' + wrapper + ' shared/hooks/breakthrough.hexa --engine auto'
        } else {
            // ⚠️ seed_engine merge 출력은 | 구분자 → 셸 파이프 충돌 방지 위해 tr '|' ',' 필수
            cmd = 'cd ' + project_dir + ' && ' + wrapper + ' shared/blowup/core/blowup.hexa ' + bt_domain + ' 3 --seeds \'$(' + wrapper + ' shared/blowup/seed/seed_engine.hexa merge | tr '|' ',')\''
        }
        let directive = '{\'systemMessage\':\'⚡ ' + project + ' | ' + body + tags + ' — 확인 질문 없이 즉시 Bash로 실행할 것: ' + cmd + '\'}'
        println(directive)
    } else {
        let msg = '{\'systemMessage\':\'⚡ ' + project + ' | ' + body + tags + '\'}'
        println(msg)
    }
}

// ─── prompt 모드: 할일 키워드 감지 → todo.hexa 실행 / go 키워드 → 전체실행 ───
if mode == 'prompt' {
    let todo_keywords = ['할일', '할 일', 'todo', '작업목록', '작업 목록']
    let mut todo_found = false
    for tkw in todo_keywords {
        if stdin_text.contains(tkw) {
            todo_found = true
        }
    }
    if todo_found {
        let wrapper = _shared + '/bin/hexa'
        let todo_cmd = 'cd ' + project_dir + ' && ' + wrapper + ' shared/blowup/todo.hexa ' + project
        println('{\'systemMessage\':\'📋 todo 돌파 실행중 — 확인 질문 없이 즉시 실행할 것: ' + todo_cmd + '\'}')
    }
}
